mapper.select:
SELECT id, name, description, category_id, type_id, resource_group, create_user, author, series_name, model_size, max_seq_length, create_time, update_time
FROM model
WHERE id = #{modelId}

SELECT id, model_id, version_number, pvc_name, internal_path, source_type, nfs_server, nfs_path, weight_type, is_registered, status, is_locked, train_frame, train_type, train_strategy, train_time, final_loss, source_version, create_time, update_time
FROM model_version
WHERE id = #{versionId} AND model_id = #{modelId}




SELECT id, name, description, category_id, type_id, resource_group, create_user, author, series_name, model_size, max_seq_length, create_time, update_time
FROM model

    AND category_id = #{condition.categoryId}
    AND type_id = #{condition.typeId}

        AND (name LIKE CONCAT('%', #{condition.keyword}, '%') OR description LIKE CONCAT('%', #{condition.keyword}, '%'))


        AND id IN (SELECT model_id FROM model_tag WHERE tag_id = #{condition.tagId})


ORDER BY create_time DESC
LIMIT #{pageSizeVal} OFFSET #{offsetVal}

SELECT COUNT(*)
FROM model

    AND category_id = #{condition.categoryId}
    AND type_id = #{condition.typeId}

        AND (name LIKE CONCAT('%', #{condition.keyword}, '%') OR description LIKE CONCAT('%', #{condition.keyword}, '%'))


        AND id IN (SELECT model_id FROM model_tag WHERE tag_id = #{condition.tagId})




